package by.sorface.passport.web.config.securityimport by.sorface.passport.web.config.options.CookieOptionsimport by.sorface.passport.web.config.options.EndpointOptionsimport by.sorface.passport.web.config.security.csrf.CsrfCookieFilterimport by.sorface.passport.web.config.security.csrf.LocaleCookieFilterimport by.sorface.passport.web.config.security.handlers.SavedRequestRedisSuccessHandlerimport by.sorface.passport.web.constants.UrlPatternEnumimport by.sorface.passport.web.services.users.providers.OAuth2UserDatabaseStrategyimport lombok.RequiredArgsConstructorimport lombok.extern.slf4j.Slf4jimport org.springframework.context.annotation.Beanimport org.springframework.context.annotation.Configurationimport org.springframework.http.HttpMethodimport org.springframework.security.config.Customizerimport org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilderimport org.springframework.security.config.annotation.authentication.configuration.EnableGlobalAuthenticationimport org.springframework.security.config.annotation.method.configuration.EnableMethodSecurityimport org.springframework.security.config.annotation.web.builders.HttpSecurityimport org.springframework.security.config.annotation.web.configuration.EnableWebSecurityimport org.springframework.security.config.annotation.web.configurers.*import org.springframework.security.config.annotation.web.configurers.AuthorizeHttpRequestsConfigurer.AuthorizationManagerRequestMatcherRegistryimport org.springframework.security.config.annotation.web.configurers.oauth2.client.OAuth2LoginConfigurerimport org.springframework.security.config.annotation.web.configurers.oauth2.client.OAuth2LoginConfigurer.UserInfoEndpointConfigimport org.springframework.security.crypto.bcrypt.BCryptPasswordEncoderimport org.springframework.security.crypto.password.PasswordEncoderimport org.springframework.security.web.SecurityFilterChainimport org.springframework.security.web.authentication.AuthenticationFailureHandlerimport org.springframework.security.web.authentication.AuthenticationSuccessHandlerimport org.springframework.security.web.authentication.www.BasicAuthenticationFilterimport org.springframework.security.web.csrf.CookieCsrfTokenRepositoryimport org.springframework.security.web.csrf.CsrfAuthenticationStrategyimport org.springframework.security.web.csrf.CsrfTokenRepositoryimport org.springframework.security.web.csrf.CsrfTokenRequestHandlerimport org.springframework.security.web.savedrequest.HttpSessionRequestCacheimport org.springframework.security.web.util.matcher.AntPathRequestMatcher@Slf4j@RequiredArgsConstructor@EnableWebSecurity@EnableMethodSecurity@EnableGlobalAuthentication@Configuration(proxyBeanMethods = false)open class SecurityConfig(private val oAuth2UserDatabaseStrategy: OAuth2UserDatabaseStrategy) {    @Bean    @Throws(Exception::class)    open fun defaultSecurityFilterChain(        httpSecurity: HttpSecurity,        savedRequestRedisSuccessHandler: SavedRequestRedisSuccessHandler,        authenticationFailureHandler: LoginFailureHandler,        apiAuthenticationEntryPoint: ApiAuthenticationEntryPoint?,        cookieCsrfTokenRepository: CookieCsrfTokenRepository,        csrfTokenRequestHandler: CsrfTokenRequestHandler,        cookieOptions: CookieOptions,        endpointOptions: EndpointOptions    ): SecurityFilterChain {        httpSecurity.getSharedObject(AuthenticationManagerBuilder::class.java)        httpSecurity.oauth2Login(            oAuth2LoginConfigurerCustomizer(oAuth2UserDatabaseStrategy, endpointOptions, savedRequestRedisSuccessHandler, authenticationFailureHandler)        )        return httpSecurity            .requestCache { httpSecurityRequestCacheConfigurer: RequestCacheConfigurer<HttpSecurity?> ->                val httpSessionRequestCache = HttpSessionRequestCache()                httpSessionRequestCache.setRequestMatcher(AntPathRequestMatcher("/oauth2/**"))                httpSecurityRequestCacheConfigurer.requestCache(httpSessionRequestCache)            }            .addFilterAfter(LocaleCookieFilter(), BasicAuthenticationFilter::class.java)            .csrf(csrfConfigurerCustomizer(cookieCsrfTokenRepository, csrfTokenRequestHandler, endpointOptions))            .addFilterAfter(CsrfCookieFilter(), BasicAuthenticationFilter::class.java)            .authorizeHttpRequests { configure ->                configure                    .requestMatchers("/v3/api-docs/**", "/swagger-ui/**", "/swagger-ui.html").permitAll() // swagger disable                    .requestMatchers("/api/accounts/signup").anonymous()                    .requestMatchers("/api/accounts/test").permitAll()                    .requestMatchers("/actuator/health/liveness").permitAll()                    .requestMatchers("/actuator/health/readiness").permitAll()                    .requestMatchers(HttpMethod.GET, "/api/accounts/locale").permitAll()                    .requestMatchers(HttpMethod.POST, "/api/accounts/locale").permitAll()                    .requestMatchers("/api/accounts/passwords/**").anonymous()                    .requestMatchers(HttpMethod.OPTIONS, *UrlPatternEnum.toArray(UrlPatternEnum.OPTION_REQUEST)).permitAll()                    .requestMatchers(HttpMethod.GET, *UrlPatternEnum.toArray(UrlPatternEnum.CSRF)).permitAll()                    .requestMatchers(HttpMethod.GET, *UrlPatternEnum.toArray(UrlPatternEnum.API_ACCOUNT)).permitAll()                    .requestMatchers(HttpMethod.POST, "/api/accounts/signin").permitAll()                    .requestMatchers(*UrlPatternEnum.toArray()).permitAll()                    .anyRequest()                    .authenticated()            }            .logout(logoutConfigurerCustomizer(endpointOptions, cookieOptions))            .formLogin(formLoginConfigurerCustomizer(endpointOptions, savedRequestRedisSuccessHandler, authenticationFailureHandler))            .exceptionHandling { exceptionHandlingConfigurer: ExceptionHandlingConfigurer<HttpSecurity?> ->                exceptionHandlingConfigurer.authenticationEntryPoint(                    apiAuthenticationEntryPoint                )            }            .build()    }    @Bean    open fun passwordEncoder(): PasswordEncoder = BCryptPasswordEncoder(10)    private fun oAuth2LoginConfigurerCustomizer(        oAuth2UserDatabaseStrategy: OAuth2UserDatabaseStrategy?,        endpointOptions: EndpointOptions,        authenticationSuccessHandler: AuthenticationSuccessHandler,        authenticationFailureHandler: AuthenticationFailureHandler    ): Customizer<OAuth2LoginConfigurer<HttpSecurity?>> {        return Customizer { configurer: OAuth2LoginConfigurer<HttpSecurity?> ->            configurer.userInfoEndpoint { configure -> configure.userService(oAuth2UserDatabaseStrategy) }            configurer.loginPage(endpointOptions.uriPageSignIn)            configurer.successHandler(authenticationSuccessHandler)            configurer.failureHandler(authenticationFailureHandler)        }    }    private fun formLoginConfigurerCustomizer(        endpointOptions: EndpointOptions,        authenticationSuccessHandler: AuthenticationSuccessHandler,        authenticationFailureHandler: AuthenticationFailureHandler    ): Customizer<FormLoginConfigurer<HttpSecurity?>> {        return Customizer { configurer: FormLoginConfigurer<HttpSecurity?> ->            configurer.loginPage(endpointOptions.uriPageSignIn)            configurer.loginProcessingUrl(endpointOptions.uriApiLogin)            configurer.successHandler(authenticationSuccessHandler)            configurer.failureHandler(authenticationFailureHandler)        }    }    private fun csrfConfigurerCustomizer(        csrfTokenRepository: CsrfTokenRepository,        csrfTokenRequestHandler: CsrfTokenRequestHandler,        endpointOptions: EndpointOptions    ): Customizer<CsrfConfigurer<HttpSecurity?>> {        return Customizer { csrfConfigurer: CsrfConfigurer<HttpSecurity?> ->            csrfConfigurer.ignoringRequestMatchers(                AntPathRequestMatcher.antMatcher(HttpMethod.GET),                AntPathRequestMatcher.antMatcher(HttpMethod.POST, endpointOptions.uriApiLogin)            )            csrfConfigurer.csrfTokenRepository(csrfTokenRepository)            csrfConfigurer.csrfTokenRequestHandler(csrfTokenRequestHandler)            csrfConfigurer.sessionAuthenticationStrategy(CsrfAuthenticationStrategy(csrfTokenRepository))        }    }    private fun logoutConfigurerCustomizer(endpointOptions: EndpointOptions, cookieOptions: CookieOptions): Customizer<LogoutConfigurer<HttpSecurity?>> {        return Customizer { configurer: LogoutConfigurer<HttpSecurity?> ->            configurer.invalidateHttpSession(true)            configurer.clearAuthentication(true)            configurer.logoutUrl(endpointOptions.uriApiLogout)            configurer.deleteCookies(cookieOptions.session!!.name, cookieOptions.csrf!!.name)        }    }}